// // This module implements a 3-bit synchronous counter that decrements its value on each positive edge of the clock signal clk. When the reset signal rst_n is high, the counter resets to seven (3'b111).
module async_counter(
    input clk,
    input rst_n,
    output reg [2:0] count
);
    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            count <= 3'b000;
        end else begin
            count <= count + 1;
        end
    end
endmodule
